def assess_trifecta(agent):
    has_untrusted = agent.processes_external_data
    has_tools = agent.can_execute_actions
    has_egress = agent.can_send_outbound

    if all([has_untrusted, has_tools, has_egress]):
        return 'CRITICAL: Lethal trifecta present'
    else:
        return 'Safer: Trifecta broken'

# Break one: no egress for untrusted data handlers
if agent.processes_untrusted:
    agent.disable_egress()
